import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"2.3.属性概述","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/2.建卡相关/2.3.属性概述.md","filePath":"1.基础规则/2.建卡相关/2.3.属性概述.md"}'),s={name:"1.基础规则/2.建卡相关/2.3.属性概述.md"};function o(_,b,d,l,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"_2-3-属性概述",tabindex:"-1"},[t("2.3.属性概述 "),r("a",{class:"header-anchor",href:"#_2-3-属性概述","aria-label":'Permalink to "2.3.属性概述"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002A")])])],-1),n('<h1 id="属性概述" tabindex="-1">属性概述 <a class="header-anchor" href="#属性概述" aria-label="Permalink to &quot;属性概述&quot;">​</a></h1><p>属性概述<br> 属性代表了人物自身具有的能力，这些能力基于天生，并且可以后天锻炼。任何正常人的每一项属性值都至少为1。<br> 提升1点属性等级需要500分。<br> 而内在强化（见资源与本质）通常也会提供自由属性点<br> 对应关系为：<br> D级内在强化提供2属性点<br> C级内在强化提供4属性点<br> B级内在强化提供8属性点<br> A级内在强化提供16属性点<br> S级内在强化提供32属性点<br> 人物的绝大多数判定都需要依据自身的属性，因此属性就相当于人物的能动能力和行为的可能性，并且有时也等同于你保持自身不被干扰或侵害的能力。若人物拥有某种超自然的本质或特性，属性也可能以超自然的形式发生作用。<br> 属性值表示人物在这一方面的能力如何。一般而言，属性值2是现代人类的平均水准，而属性值6差不多是正常人类所能达到的极限。</p><p>力量：</p><p>推拉物体、举起重物等的相关属性，包括了爆发力和负重能力，因此也影响奔走或挥动物体的速度、击打时所能造成的伤害程度。<br> 任何能够对物体施加物理作用的存在都拥有力量值。<br> 一点：穿衣服都有些吃力。<br> 两点：有正常人的力量。<br> 三点：力大无比<br> 四点：丰筋多力，肌肉怪兽<br> 五点：你不会觉得孔子仅靠仁德同他人讲理和周游列国吧（鬼背孔子.jpg）<br> 六点：力拔山兮气盖世，五马齐驱不能移</p><p>敏捷：</p><p>全身的协调能力、动作的精确性和灵活性、反应神经等，快速有效运动身体的能力。<br> 任何能够活动和移动的物体都拥有敏捷值。<br> 一点：像是木偶<br> 两点：体测勉强合格<br> 三点：是一位运动健将<br> 四点：香港记者里的短跑冠军<br> 五点：人们可能只会感到有一只大黑耗子（划掉）一阵风过去了<br> 六点：程途八百里，朝去暮还来。</p><p>耐力：</p><p>身体的健康程度和抵抗力、新陈代谢的活跃度等，抵挡伤病的能力。<br> 任何活着的东西都拥有耐力值。<br> 一点：常年患病在身<br> 两点：不会生什么大病<br> 三点：健硕而不惧病害<br> 四点：马拉松健将<br> 五点：战场上最勇猛的老兵<br> 六点：无垢仙躯，百折不挠</p><p>智力：</p><p>逻辑思维的能力、计算能力、分析能力和记忆力等，有时也代表了人物对超自然能量的分配和控制。请注意，虽然下面以IQ举例，但智力跟智商并没有直接关系，智力1的人也可以设置精妙的布局（即使他可能平时经常丢三落四）。<br> 任何能够理解语言并且能进行分析和推理的存在都拥有智力值。<br> 一点：脑子？啥<br> 两点：有着普通人的灵光一现<br> 三点：你解决过很多数学难题<br> 四点：可以自主进行发明创造<br> 五点：你的智商位于世界的顶峰<br> 六点：鬼才多智近乎妖</p><p>感知：</p><p>留意环境并查觉变化的能力，洞察力、直觉、快速分辨细节的能力。这一属性代表人物的注意力和对信息的分辨能力，因此近视眼不一定感知就低。在超自然的意义上，感知代表了人物能在多细微的程度上感应超自然能量。<br> 任何能够感知外界的存在都拥有感知值。<br> 一点：你总是会遗忘掉重要的信息。<br> 两点：可能忽略小细节<br> 三点：掌握周围的各项小细节。<br> 四点：眼角能瞥到雪地里的反光<br> 五点：我焯！你找到越共了！<br> 六点：烧犀观火，洞幽烛微</p><p>决心：</p><p>人物果敢的决断力和决定的坚定程度，也代表了人物顽固的程度。在超自然意义上，代表了人物的精神的强度。<br> 任何能够有目的行动的存在都拥有决心值。<br> 一点：欺诈团伙的常客<br> 两点：如常人一般会有一定自制力<br> 三点：你能拒绝大部分诱惑<br> 四点：（在巨大的诱惑面前）你的表现像是戒过毒<br> 五点：山崩于前面不改色<br> 六点：精神钢印</p><p>风度：</p><p>人物的气质、风度和存在感，不由地引起旁人兴趣的能力。在超自然意义上，也代表了人物在多大程度上超脱了自然本质。虽然与相貌有关，但数值高并不意味着长得帅或美丽，数值低也不一定是丑八怪。<br> 任何能够将自己与环境区分开的存在都拥有风度值。<br> 一点：路人里的透明<br> 两点：可以交个朋友<br> 三点：不完全是个陌生人<br> 四点：人们会不由自主地想要靠近你<br> 五点：国民偶像无论在哪里出现都会成为焦点<br> 六点：万物倾倒，众生痴迷</p><p>操控：</p><p>影响他人的能力，言行的感染力，煽动别人、让别人依你的想法行事的能力。在超自然的意义上，这也代表了人物支配某些超自然或灵性的存在的能力。 <br> 任何能够表达自己意愿的存在都拥有操控值。任何操控值达到2或更高的个体，都应该具有某种明确、主动、自觉表达自己意图的手段，如语言。一个眼神可能也算是操控。<br> 一点：你的话更像是游戏旁白，还是那种无关紧要的。<br> 两点：可以忽悠你的妈妈去揍你哥哥<br> 三点：房地产销售冠军<br> 四点：人们会无脑的听从你的指示<br> 五点：伟大的元首！！！Heil Hitler！！！<br> 六点：一怒而天下惧，安居而天下熄</p><p>沉着：</p><p>镇定自若的能力，头脑的反应速度，在压力下或紧急情况下保持冷静的能力。在超自然意义上，代表了人物心智的活力。 <br> 一点：电影里除了哭就会叫反应慢还死坐在地上的早死配角。<br> 两点：在危机来临时，你能尽力克制住不尿裤子并尝试动脑。<br> 三点：你能稳住颤抖的身体并快速思考。<br> 四点：能够超前别人的想法。<br> 五点：在别人理清问题之前，你已经有答案了。<br> 六点：风雨不动安如山，七步成才狂如仙</p><p>传奇属性</p><p>关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的1DP增强加值与1点附加成功，可携带物品体积额外提升4点<br> 敏捷上的每1点附加成功会在回合开始时额外提供1点基础Ap并提高3米额外移速<br> 耐力上的每1点附加成功会为其提供5点生命值</p><p>智力上的每1点附加成功会为其提供每场景一次，在进行某个检定时可以将1个失败骰转为成功骰的能力，每有2点智力附加成功就能额外将一个失败骰转为成功骰，这一能力不能在一次检定中多次使用<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升或者获得1点全检定上的机运加值，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰以及在进行短休息后额外恢复1点意志力</p><p>特殊：如果一个人物在属性上不具有内在支线强化，那么就不能享受到属性上的附加成功及其带来的好处。</p><p>属性值为0和空属性</p><p>属性值降低代表人物在某些方面受到了损伤，可能是身体，也可能是精神或灵魂。若属性值降为0，则人物会失去自主行动力——在游戏进行中，玩家失去了对人物的控制权。<br> 力量为0的人物不能移动，无法承受自身的重量也无法移动肢体。他将会倒在地上。<br> 敏捷为0的人物不能活动，关节僵死。若他的姿势恰当，他会僵硬无助地站着或蹲着，否则他会倒地。<br> 耐力为0的人物会死亡。<br> 智力为0的人物失去自主行动能力，会依原始本能行动，不记得任何东西也无法使用任何技能（除了移动身体和逃避危险）。<br> 感知为0的人物失去对现实的感应，陷入无法醒来的迷梦。<br> 决心为0的人物失去行为能力，只会漫无目地的呆坐或徘徊，无法使用任何技能并失去对现实的反应（包括对危险的反应）。<br> 风度为0的人物失去意识。<br> 操控为0的人物会完全精神失常并疯狂，无法进行任何可理解或有意义的行为。<br> 沉着为0的人物失去行为能力和自制力，完全精神失常，不做任何行动且失去对现实的反应。</p><p>有些存在天生没有某些属性，这称为空属性。空属性的存在无法进行相关判定，也不会受到属性降低的效果。<br> 以下是空属性的一些范例：<br> 普通的物品没有任何属性。机械装置拥有力量值，其敏捷值取决于操纵者的敏捷或技能。预编程和可以自行工作的电脑等设备拥有智力值。<br> 动物没有智力值，它们没有理解语言和进行逻辑思维的能力。<br> 普通的植物只有耐力值。它们同时拥有硬度值，但生命值依耐力值而决定。某些超自然的植物可能拥有其他属性。<br> 属性等级第一次达到6级时获得1点附加成功，此后每5级获得1点。每个等级并无属性最高等级限制，但最低等级的属性不能低于最高等级的属性8级。</p><p>特殊：不论以任何手段获得的额外属性点，都无法超过属性上限。</p><p>[此处为建立人物卡以继续游戏回链</p><p>](2.1.建立人物卡以继续游戏.html)</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',33)])])}const m=p(s,[["render",o]]);export{f as __pageData,m as default};
